    /// Space must type as a literal space in every plain-text dialog field — regression test
    /// for a real bug found while auditing dialog UX consistency: `KeyCode::Char(' ')` was
    /// unconditionally intercepted for ALL dialogs (only four actually use it, as a checkbox/
    /// toggle key), so no free-text field anywhere in the app — CDP browser search, Rename
    /// Buffer/File/Marker, Open Directory, Save Curve As, Load Pitch Curve, CDP Setup — could
    /// ever contain a space; the keystroke was silently dropped with no feedback at all.
    /// Covers a search box (multi-word query) and a rename dialog (a name with a space).
    #[test]
    fn space_types_a_literal_space_in_plain_text_dialogs() {
        let mut app = new_app(Some(doc(0.1, 44100)), None);
        app.open_cdp_browser();
        type_str(&mut app, "psow stretch");
        let Some(Dialog::CdpBrowser { search, .. }) = &app.dialog else { panic!("no dialog") };
        assert_eq!(search.value(), "psow stretch");

        let mut app = new_app(Some(doc(0.1, 44100)), None);
        app.dialog = Some(Dialog::RenameBuffer { index: 0, input: TextInput::fresh(String::new()) });
        type_str(&mut app, "my new name");
        let Some(Dialog::RenameBuffer { input, .. }) = &app.dialog else { panic!("no dialog") };
        assert_eq!(input.value(), "my new name");
    }

    /// `App::cdp_groups` always starts with `CDP_GROUP_ALL` then `CDP_GROUP_RECENT`,
    /// followed by every real `subcategory` in the catalog, alphabetically sorted with no
    /// duplicates — the taxonomy `scripts/convert_soundthread_catalog.py` reconciles down to
    /// one clean set (CDP-Ext-Plan.md Phase 7).
    #[test]
    fn cdp_groups_lists_all_recent_then_alphabetical_subcategories() {
        let app = new_app(Some(doc(0.1, 100)), None);
        let groups = app.cdp_groups();
        assert_eq!(groups[0], CDP_GROUP_ALL);
        assert_eq!(groups[1], CDP_GROUP_RECENT);
        let subcategories = &groups[2..];
        assert!(!subcategories.is_empty(), "the real catalog has real subcategories");
        let mut sorted = subcategories.to_vec();
        sorted.sort();
        sorted.dedup();
        assert_eq!(subcategories, sorted.as_slice(), "should already be sorted with no duplicates");
    }

    /// Regression (user report, 2026-07-21): "pitch curve" is a real `subcategory` in the
    /// catalog, but every process tagged with it is curve-in/curve-out and therefore
    /// excluded from this browser entirely (`cdp_browser_never_lists_curve_only_processes`
    /// below) — so before this fix, highlighting "pitch curve" always showed "No matches", a
    /// dead-end group with no way out. `cdp_groups` must not list any group that
    /// `cdp_filter_entries` can never populate; every group it *does* list must return at
    /// least one entry from "All"'s own eligible set.
    #[test]
    fn cdp_groups_never_lists_a_group_the_browser_can_only_ever_show_empty() {
        let app = new_app(Some(doc(0.1, 100)), None);
        let groups = app.cdp_groups();
        assert!(!groups.iter().any(|g| g == "pitch curve"), "\"pitch curve\" only has curve-only entries -- it must be filtered out");
        for group in &groups[2..] {
            let entries = app.cdp_filter_entries("", group, &[]);
            assert!(!entries.is_empty(), "group {group:?} is listed but has no eligible entries");
        }
    }

    /// Chain-mode filtering (`cdp_chain_edit_target.is_some()`): synthesis (`IoKind::None`)
    /// and glob-output processes must be excluded from the picker, since neither composes
    /// into "feeds the next step's audio input" (`CDP-CHAIN-PLAN.md` design decision 3) —
    /// but an ordinary Wav/Ana single-input process must still show up.
    #[test]
    fn chain_edit_mode_excludes_synthesis_and_glob_output_processes_from_the_browser() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        app.cdp_chain_edit_target = Some(ChainEditTarget::Append(Vec::new()));
        let entries = app.cdp_filter_entries("", CDP_GROUP_ALL, &[]);
        let keys: Vec<&str> = entries.iter().map(|&i| app.cdp_catalog.processes[i].key.as_str()).collect();

        assert!(!keys.contains(&"synth_wave_1"), "a synthesis process (no real input) must not appear while building a chain");
        assert!(!keys.contains(&"distcut_distcut_1"), "a glob-output process (many results, not one) must not appear while building a chain");
        assert!(keys.contains(&"blur_avrg"), "an ordinary chainable process must still appear");

        app.cdp_chain_edit_target = None;
        let entries = app.cdp_filter_entries("", CDP_GROUP_ALL, &[]);
        let keys: Vec<&str> = entries.iter().map(|&i| app.cdp_catalog.processes[i].key.as_str()).collect();
        assert!(keys.contains(&"synth_wave_1"), "outside chain mode, synthesis processes are normal browser entries");
    }

    fn chain_step(key: &str) -> crate::model::cdp::ChainStep {
        crate::model::cdp::ChainStep { process_key: key.into(), values: Vec::new(), side_chain: Vec::new() }
    }

    fn fresh_chain_editor_state(chain: crate::model::cdp::CdpChain) -> ChainEditorState {
        ChainEditorState {
            chain,
            buffer_picks: std::collections::HashMap::new(),
            selected: ChainEditorRow::Preset,
            error: None,
            presets: Vec::new(),
            preset_selected: None,
            save_prompt: None,
        }
    }

    /// `chain_editor_rows` must place a dual-input step's side-chain steps directly beneath
    /// it, followed by its own "add side-chain step" row, before moving on to the next main
    /// step — the ordering the chain editor's Up/Down navigation and rendering both rely on.
    /// Nested 3 levels deep (a side-chain step that's itself dual-input with its own
    /// side-chain) to prove the unlimited-depth rewrite actually recurses, not just handles
    /// one extra level.
    #[test]
    fn chain_editor_rows_nests_side_chain_steps_to_any_depth() {
        let app = new_app(Some(doc(0.1, 100)), None);
        let mut middle_dual = crate::model::cdp::ChainStep {
            process_key: "combine_mean_1".into(),
            values: Vec::new(),
            side_chain: vec![chain_step("blur_avrg")],
        };
        let outer_dual = crate::model::cdp::ChainStep {
            process_key: "combine_mean_1".into(),
            values: Vec::new(),
            side_chain: vec![{
                middle_dual.side_chain.push(chain_step("focus_freeze_1"));
                middle_dual
            }],
        };
        let state = fresh_chain_editor_state(crate::model::cdp::CdpChain {
            name: "test".into(),
            steps: vec![outer_dual, chain_step("blur_avrg")],
        });
        let rows = chain_editor_rows(&state, &app.cdp_catalog);
        assert_eq!(
            rows,
            vec![
                ChainEditorRow::Preset,
                ChainEditorRow::Step(vec![0]),                      // outer_dual
                ChainEditorRow::Step(vec![0, 0]),                   // middle_dual, nested under step 0's side-chain
                ChainEditorRow::Step(vec![0, 0, 0]),                // blur_avrg, nested under [0,0]'s side-chain
                ChainEditorRow::Step(vec![0, 0, 1]),                // focus_freeze_1, blur_avrg's sibling (neither is dual-input, so no AddStep between them)
                ChainEditorRow::AddStep(vec![0, 0]),                // "+ Add step" for middle_dual's own side-chain (it IS dual-input)
                ChainEditorRow::AddStep(vec![0]),                   // "+ Add step" for outer_dual's own side-chain
                ChainEditorRow::Step(vec![1]),                      // blur_avrg, sibling of outer_dual at the top level
                ChainEditorRow::AddStep(Vec::new()),                // "+ Add step" for the main chain itself
                ChainEditorRow::Preview,
                ChainEditorRow::Run,
            ]
        );
    }

    /// `chain_display_rows` must interleave "PVOC Analyze"/"PVOC Resynthesize" exactly
    /// bracketing a run of adjacent single-input spectral steps — merged into ONE shared
    /// pair for the whole run, not one pair per step — while leaving a plain time-domain
    /// step (and the rows around it) completely untouched.
    #[test]
    fn chain_display_rows_brackets_a_run_of_adjacent_spectral_steps() {
        let app = new_app(Some(doc(0.1, 100)), None);
        let state = fresh_chain_editor_state(crate::model::cdp::CdpChain {
            name: "test".into(),
            steps: vec![chain_step("phase_phase_1"), chain_step("blur_avrg"), chain_step("blur_avrg")],
        });
        let rows = chain_display_rows(&state, &app.cdp_catalog);
        assert_eq!(
            rows,
            vec![
                DisplayRow::Row(ChainEditorRow::Preset),
                DisplayRow::Row(ChainEditorRow::Step(vec![0])), // phase_phase_1 -- time-domain, no bracket
                DisplayRow::PvocAnalyze { depth: 1 },
                DisplayRow::Row(ChainEditorRow::Step(vec![1])), // blur_avrg
                DisplayRow::Row(ChainEditorRow::Step(vec![2])), // blur_avrg -- merged into the same run, no anal/synth between them
                DisplayRow::PvocResynthesize { depth: 1 },
                DisplayRow::Row(ChainEditorRow::AddStep(Vec::new())),
                DisplayRow::Blank,
                DisplayRow::Row(ChainEditorRow::Preview),
                DisplayRow::Row(ChainEditorRow::Run),
            ]
        );
    }

    /// A dual-input spectral step (`combine_mean_1`, `IoKind::DualAna`) never merges into a
    /// run with an adjacent single-input spectral sibling, even though both are "[pvoc]" —
    /// it always gets its own isolated anal/synth bracket, matching `plan_dual_ana`'s real
    /// behavior (which always wraps itself independent of its neighbors) and
    /// `ana_run_length`'s own exclusion of dual-input steps from a mergeable run.
    #[test]
    fn chain_display_rows_never_merges_a_dual_input_spectral_step_with_a_neighbor() {
        let app = new_app(Some(doc(0.1, 100)), None);
        let state = fresh_chain_editor_state(crate::model::cdp::CdpChain {
            name: "test".into(),
            steps: vec![chain_step("blur_avrg"), chain_step("combine_mean_1")],
        });
        let rows = chain_display_rows(&state, &app.cdp_catalog);
        assert_eq!(
            rows,
            vec![
                DisplayRow::Row(ChainEditorRow::Preset),
                DisplayRow::PvocAnalyze { depth: 1 },
                DisplayRow::Row(ChainEditorRow::Step(vec![0])), // blur_avrg -- its own isolated bracket
                DisplayRow::PvocResynthesize { depth: 1 },
                DisplayRow::PvocAnalyze { depth: 1 },
                DisplayRow::Row(ChainEditorRow::Step(vec![1])), // combine_mean_1 -- its own isolated bracket, not merged with blur_avrg
                DisplayRow::PvocResynthesize { depth: 1 },
                DisplayRow::Row(ChainEditorRow::AddStep(vec![1])), // combine_mean_1 is dual-input -- has its own side-chain "+ Add step"
                DisplayRow::Row(ChainEditorRow::AddStep(Vec::new())),
                DisplayRow::Blank,
                DisplayRow::Row(ChainEditorRow::Preview),
                DisplayRow::Row(ChainEditorRow::Run),
            ]
        );
    }

    /// Reordering steps must recompute where the bracket lands, exactly as the feature asks:
    /// "every time the order and amount of processes in the chain is changed... the chain
    /// display should be recalculated." `chain_display_rows` is never cached (rebuilt fresh
    /// from `state.chain` every call), so reordering the underlying steps alone -- without
    /// touching `chain_display_rows` at all -- must already move the bracket to the step's
    /// new position.
    #[test]
    fn reordering_steps_moves_the_pvoc_bracket_to_follow_the_step() {
        let app = new_app(Some(doc(0.1, 100)), None);
        let mut state = fresh_chain_editor_state(crate::model::cdp::CdpChain {
            name: "test".into(),
            steps: vec![chain_step("blur_avrg"), chain_step("phase_phase_1")],
        });
        let before = chain_display_rows(&state, &app.cdp_catalog);
        assert_eq!(before[1], DisplayRow::PvocAnalyze { depth: 1 }, "sanity: bracket starts around step 0 (blur_avrg)");

        state.chain.steps.swap(0, 1); // now [phase_phase_1, blur_avrg]
        let after = chain_display_rows(&state, &app.cdp_catalog);
        assert_eq!(
            after,
            vec![
                DisplayRow::Row(ChainEditorRow::Preset),
                DisplayRow::Row(ChainEditorRow::Step(vec![0])), // phase_phase_1, now first -- no bracket
                DisplayRow::PvocAnalyze { depth: 1 },
                DisplayRow::Row(ChainEditorRow::Step(vec![1])), // blur_avrg, now second -- bracket followed it here
                DisplayRow::PvocResynthesize { depth: 1 },
                DisplayRow::Row(ChainEditorRow::AddStep(Vec::new())),
                DisplayRow::Blank,
                DisplayRow::Row(ChainEditorRow::Preview),
                DisplayRow::Row(ChainEditorRow::Run),
            ]
        );
    }

    /// The synthetic PVOC rows are purely a rendering concern: they never appear in
    /// `chain_editor_rows` (the list navigation/selection actually uses), so Up/Down and
    /// `state.selected` can never land on one no matter how many are interleaved into the
    /// rendered display.
    #[test]
    fn pvoc_display_rows_are_absent_from_the_selectable_row_list() {
        let app = new_app(Some(doc(0.1, 100)), None);
        let state = fresh_chain_editor_state(crate::model::cdp::CdpChain {
            name: "test".into(),
            steps: vec![chain_step("blur_avrg"), chain_step("blur_avrg"), chain_step("combine_mean_1")],
        });
        let display_rows = chain_display_rows(&state, &app.cdp_catalog);
        assert!(
            display_rows.iter().any(|r| matches!(r, DisplayRow::PvocAnalyze { .. } | DisplayRow::PvocResynthesize { .. })),
            "sanity: this chain should actually produce some PVOC display rows"
        );
        let selectable = chain_editor_rows(&state, &app.cdp_catalog);
        // Every real step/control row still appears, one-to-one, with none of the synthetic
        // PVOC rows mixed in.
        let display_steps: Vec<_> = display_rows
            .into_iter()
            .filter_map(|r| match r { DisplayRow::Row(row) => Some(row), _ => None })
            .collect();
        assert_eq!(display_steps, selectable, "the selectable list must be exactly the display list with PVOC rows stripped out");
    }

    /// End-to-end through the real key-handling path (not calling internal helpers directly):
    /// opening the chain editor, adding a step via the reused Browser/Params flow, and
    /// committing it via the Apply-row Enter redirect (`cdp_chain_commit_step`) must leave
    /// exactly one step in the draft with that process's default values.
    #[test]
    fn adding_a_step_through_the_real_browser_and_params_flow_lands_in_the_draft() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        app.config.cdp_dir = std::path::Path::new(env!("CARGO_MANIFEST_DIR")).join("cdp").to_string_lossy().to_string();

        app.handle_action(Action::CdpChain);
        assert!(matches!(app.dialog, Some(Dialog::CdpChainEditor)), "Ctrl+H should open the chain editor directly (valid cdp_dir)");

        app.open_cdp_chain_step_target(ChainEditTarget::Append(Vec::new()));
        assert!(matches!(app.dialog, Some(Dialog::CdpBrowser { .. })), "adding a step opens the (filtered) browser");
        assert_eq!(app.cdp_chain_edit_target, Some(ChainEditTarget::Append(Vec::new())));

        let blur_avrg_index =
            app.cdp_catalog.processes.iter().position(|p| p.key == "blur_avrg").expect("blur_avrg in catalog");
        app.open_cdp_params(blur_avrg_index);
        assert!(matches!(app.dialog, Some(Dialog::CdpParams { .. })));

        // Enter on the Apply row: since `cdp_chain_edit_target` is set, this must commit to
        // the draft instead of actually running a job.
        app.handle_dialog_key(KeyEvent::new(KeyCode::Enter, KeyModifiers::NONE));

        assert!(matches!(app.dialog, Some(Dialog::CdpChainEditor)), "committing a step returns to the chain editor");
        assert!(app.cdp_chain_edit_target.is_none(), "the target should be consumed once committed");
        let state = app.cdp_chain_editor.as_ref().expect("draft still exists");
        assert_eq!(state.chain.steps.len(), 1);
        assert_eq!(state.chain.steps[0].process_key, "blur_avrg");
    }

    /// 'd' on a selected step removes it (and shifts `buffer_picks` in lockstep);
    /// Shift+Up/Down swaps adjacent siblings — the two mutations
    /// `handle_cdp_chain_editor_key` maps onto `delete_chain_editor_row`/`reorder_chain_step`.
    #[test]
    fn deleting_and_reordering_steps_keeps_buffer_picks_in_lockstep() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        let mut state =
            fresh_chain_editor_state(crate::model::cdp::CdpChain { name: "t".into(), steps: vec![chain_step("blur_avrg"), chain_step("focus_freeze_1")] });
        state.selected = ChainEditorRow::Step(vec![0]);
        app.cdp_chain_editor = Some(state);

        app.reorder_chain_step(1);
        let state = app.cdp_chain_editor.as_ref().unwrap();
        assert_eq!(state.chain.steps[0].process_key, "focus_freeze_1");
        assert_eq!(state.chain.steps[1].process_key, "blur_avrg");
        assert_eq!(state.selected, ChainEditorRow::Step(vec![1]));

        app.cdp_chain_editor.as_mut().unwrap().selected = ChainEditorRow::Step(vec![0]);
        app.delete_chain_editor_row();
        let state = app.cdp_chain_editor.as_ref().unwrap();
        assert_eq!(state.chain.steps.len(), 1);
        assert_eq!(state.chain.steps[0].process_key, "blur_avrg");
        assert!(state.buffer_picks.is_empty());
    }

    /// 'l' loads whatever chain `chain_last::save_last_chain` most recently persisted into the
    /// draft — end to end through the real key-handling path, not the lower-level helper
    /// directly — clearing any stale `buffer_picks`/`preset_selected` from before the load.
    #[test]
    fn l_key_recalls_the_last_run_chain_via_real_key_handling() {
        let _guard = crate::config::XDG_CONFIG_HOME_TEST_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        let temp_dir = std::env::temp_dir().join(format!("tui_wave_cdp_chain_last_key_test_{}", std::process::id()));
        std::fs::create_dir_all(&temp_dir).unwrap();
        unsafe { std::env::set_var("XDG_CONFIG_HOME", &temp_dir) };

        let last_chain = crate::model::cdp::CdpChain {
            name: "Auto-saved run".into(),
            steps: vec![chain_step("blur_avrg"), chain_step("focus_freeze_1")],
        };
        crate::model::cdp::chain_last::save_last_chain(&last_chain);

        let mut app = new_app(Some(doc(0.1, 100)), None);
        let mut stale_picks = std::collections::HashMap::new();
        stale_picks.insert(vec![0], 3usize);
        let mut state = fresh_chain_editor_state(crate::model::cdp::CdpChain { name: "draft".into(), steps: Vec::new() });
        state.buffer_picks = stale_picks;
        state.preset_selected = Some(0);
        app.cdp_chain_editor = Some(state);
        app.dialog = Some(Dialog::CdpChainEditor);

        app.handle_dialog_key(KeyEvent::new(KeyCode::Char('l'), KeyModifiers::NONE));

        let state = app.cdp_chain_editor.as_ref().expect("chain editor still open");
        assert_eq!(state.chain, last_chain, "'l' should load the auto-saved chain into the draft");
        assert!(state.buffer_picks.is_empty(), "loading a chain must clear stale buffer picks, same as loading a named preset");
        assert_eq!(state.preset_selected, None, "the recalled chain isn't itself a named preset entry");
        assert!(state.error.is_none());

        unsafe { std::env::remove_var("XDG_CONFIG_HOME") };
        std::fs::remove_dir_all(&temp_dir).ok();
    }

    /// 'l' with no chain ever run shows an inline error instead of silently doing nothing.
    #[test]
    fn l_key_with_no_last_chain_shows_an_inline_error() {
        let _guard = crate::config::XDG_CONFIG_HOME_TEST_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        let temp_dir = std::env::temp_dir().join(format!("tui_wave_cdp_chain_last_key_empty_test_{}", std::process::id()));
        std::fs::create_dir_all(&temp_dir).unwrap();
        unsafe { std::env::set_var("XDG_CONFIG_HOME", &temp_dir) };

        let mut app = new_app(Some(doc(0.1, 100)), None);
        app.cdp_chain_editor = Some(fresh_chain_editor_state(crate::model::cdp::CdpChain { name: "draft".into(), steps: Vec::new() }));
        app.dialog = Some(Dialog::CdpChainEditor);

        app.handle_dialog_key(KeyEvent::new(KeyCode::Char('l'), KeyModifiers::NONE));

        let state = app.cdp_chain_editor.as_ref().expect("chain editor still open");
        assert!(state.error.is_some(), "no chain has ever been run — 'l' should surface an error, not silently no-op");

        unsafe { std::env::remove_var("XDG_CONFIG_HOME") };
        std::fs::remove_dir_all(&temp_dir).ok();
    }

    /// Reordering/deleting a step that has nested side-chain buffer picks must remap those
    /// picks' paths along with it — the real bug `remap_buffer_picks_after_swap`/
    /// `remove_buffer_picks_under` exist to prevent (a pick silently pointing at the wrong,
    /// now-shifted step after a reorder or delete).
    #[test]
    fn reordering_a_step_with_nested_buffer_picks_remaps_them() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        let dual_with_side_chain = crate::model::cdp::ChainStep {
            process_key: "combine_mean_1".into(),
            values: Vec::new(),
            side_chain: vec![chain_step("blur_avrg")],
        };
        let mut state = fresh_chain_editor_state(crate::model::cdp::CdpChain {
            name: "t".into(),
            steps: vec![chain_step("focus_freeze_1"), dual_with_side_chain],
        });
        state.buffer_picks.insert(vec![1], 2); // step 1's own second input
        state.selected = ChainEditorRow::Step(vec![1]);
        app.cdp_chain_editor = Some(state);

        app.reorder_chain_step(-1); // swap step 1 into position 0
        let state = app.cdp_chain_editor.as_ref().unwrap();
        assert_eq!(state.chain.steps[0].process_key, "combine_mean_1");
        assert_eq!(state.buffer_picks.get(&vec![0]), Some(&2), "the pick must follow the step to its new path");
        assert!(state.buffer_picks.get(&vec![1]).is_none());
    }

    /// The core "fully working picker" fix: reopening a dual-input step for editing must
    /// seed `CdpSecondInput.selected` from whatever was already picked for it
    /// (`buffer_picks`), not silently fall back to the default "first non-active document" —
    /// otherwise tweaking an unrelated param and committing would overwrite a correct earlier
    /// pick with the wrong one.
    #[test]
    fn reopening_a_chain_step_seeds_the_second_input_from_its_existing_pick() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        app.push_document(doc(0.2, 100)); // a second open document to pick as the buffer
        let mut state = fresh_chain_editor_state(crate::model::cdp::CdpChain {
            name: "t".into(),
            steps: vec![chain_step("combine_mean_1")],
        });
        state.buffer_picks.insert(vec![0], 1); // pick document index 1, not the default
        app.cdp_chain_editor = Some(state);

        app.open_cdp_chain_step_target(ChainEditTarget::Replace(vec![0]));
        let Some(Dialog::CdpParams { second_input: Some(second), .. }) = &app.dialog else {
            panic!("expected CdpParams with a second_input row for a dual-input step");
        };
        assert_eq!(second.selected_doc_index(), Some(1), "must seed from buffer_picks, not the default");
    }

    /// "Configure Side-Chain..." ('x' on the second-input row) suspends the current step's
    /// `CdpParams` session and opens the browser to append to its side-chain; committing that
    /// nested step must resume the *parent* session with its own fields intact (not jump back
    /// to the top-level chain editor) — the suspend/resume stack this feature needed. Only
    /// offered for a step already committed to the draft (a `Replace` target) — matching the
    /// chain editor's own "+ Add side-chain step" row, which likewise only appears for a step
    /// already in the tree — so this test first adds the combine step normally, then reopens
    /// it to configure its side-chain.
    #[test]
    fn configuring_a_side_chain_suspends_and_resumes_the_parent_step_session() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        app.config.cdp_dir = std::path::Path::new(env!("CARGO_MANIFEST_DIR")).join("cdp").to_string_lossy().to_string();
        let combine_index =
            app.cdp_catalog.processes.iter().position(|p| p.key == "combine_mean_1").expect("combine_mean_1 in catalog");
        app.cdp_chain_editor = Some(fresh_chain_editor_state(crate::model::cdp::CdpChain {
            name: "t".into(),
            steps: vec![crate::model::cdp::ChainStep { process_key: "combine_mean_1".into(), values: Vec::new(), side_chain: Vec::new() }],
        }));

        app.open_cdp_chain_step_target(ChainEditTarget::Replace(vec![0]));
        assert!(matches!(app.dialog, Some(Dialog::CdpParams { .. })), "an existing step's Replace target jumps straight to CdpParams");
        // Focus the second-input row so `configure_chain_side_chain` recognizes it.
        if let Some(Dialog::CdpParams { focus, fields, second_input, .. }) = app.dialog.as_mut() {
            *focus = cdp_params_focus_second_input(fields.len());
            assert!(second_input.is_some(), "combine_mean_1 is dual-input");
        }

        assert!(app.configure_chain_side_chain(), "should suspend and open the browser for the side-chain");
        assert_eq!(app.cdp_chain_edit_suspended.len(), 1, "the parent (combine) session must be suspended");
        assert!(matches!(app.dialog, Some(Dialog::CdpBrowser { .. })));

        let blur_index = app.cdp_catalog.processes.iter().position(|p| p.key == "blur_avrg").expect("blur_avrg in catalog");
        app.open_cdp_params(blur_index);
        app.handle_dialog_key(KeyEvent::new(KeyCode::Enter, KeyModifiers::NONE)); // commit the side-chain step

        assert!(app.cdp_chain_edit_suspended.is_empty(), "resuming should pop the suspend stack");
        let Some(Dialog::CdpParams { catalog_index, .. }) = &app.dialog else {
            panic!("expected to resume the parent (combine) CdpParams session, not the chain editor");
        };
        assert_eq!(*catalog_index, combine_index, "resumed session must be the outer combine step, not left on the inner one");

        // Now commit the outer (combine) step and confirm its side-chain really landed.
        app.handle_dialog_key(KeyEvent::new(KeyCode::Enter, KeyModifiers::NONE));
        assert!(matches!(app.dialog, Some(Dialog::CdpChainEditor)));
        let state = app.cdp_chain_editor.as_ref().unwrap();
        assert_eq!(state.chain.steps.len(), 1);
        assert_eq!(state.chain.steps[0].side_chain.len(), 1);
        assert_eq!(state.chain.steps[0].side_chain[0].process_key, "blur_avrg");
    }

    /// Regression (user report, 2026-07-21): `psow`'s pitch-subcategory processes (e.g.
    /// "Psow Reinforce Harmonics") are ordinary wav-in/wav-out and were never actually
    /// excluded from the "pitch" group -- they just sit at the end of its (long,
    /// catalog-order, not alphabetical) list, past what a single screenful shows.
    #[test]
    fn psow_pitch_processes_appear_in_the_real_pitch_group() {
        let app = new_app(Some(doc(0.1, 100)), None);
        let entries = app.cdp_filter_entries("", "pitch", &[]);
        // Checked by `key` prefix, not title text: titles no longer necessarily start with
        // "Psow" (see CDP-WASM-SUITE-analysis.md's rename pass — bin-name prefixes were
        // deliberately dropped from titles), but every process's `bin` field is stable and
        // `psow_`-keyed entries are exactly the ones this regression is guarding.
        let keys: Vec<&str> = entries.iter().map(|&i| app.cdp_catalog.processes[i].key.as_str()).collect();
        assert!(
            keys.iter().any(|k| k.starts_with("psow_")),
            "expected at least one psow-keyed process in the \"pitch\" group, got {keys:?}"
        );
    }

    /// Curve-in/curve-out processes (Repitch Exaggerate/Smooth/...) must never appear in the
    /// CDP browser — they can only ever be planned against an open `PitchCurve`'s binary
    /// template (`plan_curve_transform_job`), never the active document's audio, so showing
    /// them here would let a user pick one that's guaranteed to fail on Apply/Preview. They
    /// stay reachable only from the standalone curve editor's own 't' picker.
    #[test]
    fn cdp_browser_never_lists_curve_only_processes() {
        let app = new_app(Some(doc(0.1, 100)), None);
        assert!(
            app.cdp_catalog.processes.iter().any(is_curve_only_process),
            "the catalog must actually have curve-only entries for this test to mean anything"
        );
        let entries = app.cdp_filter_entries("", CDP_GROUP_ALL, &[]);
        for &i in &entries {
            assert!(
                !is_curve_only_process(&app.cdp_catalog.processes[i]),
                "{} is curve-only and must not appear in the browser",
                app.cdp_catalog.processes[i].key
            );
        }
    }

    /// Tab toggles `Dialog::CdpBrowser.group_focus`; while it's set, Up/Down move
    /// `group_selected` (re-filtering `entries`, resetting the process list's `selected` to
    /// 0) instead of the process list's own `selected` — see `App::cdp_browser_move_group`.
    #[test]
    fn tab_toggles_browser_group_focus_and_arrow_keys_follow_it() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        app.open_cdp_browser();
        let Some(Dialog::CdpBrowser { group_focus, .. }) = &app.dialog else { panic!("no dialog") };
        assert!(!group_focus, "should start with the process list focused");

        app.handle_dialog_key(KeyEvent::new(KeyCode::Tab, KeyModifiers::NONE));
        let Some(Dialog::CdpBrowser { group_focus, .. }) = &app.dialog else { panic!("no dialog") };
        assert!(*group_focus);

        app.handle_dialog_key(KeyEvent::new(KeyCode::Down, KeyModifiers::NONE));
        let Some(Dialog::CdpBrowser { group_selected, selected, .. }) = &app.dialog else { panic!("no dialog") };
        assert_eq!(*group_selected, 1, "Down while group-focused should move group_selected, not selected");
        assert_eq!(*selected, 0, "the process list's own selection is untouched by a group move");

        app.handle_dialog_key(KeyEvent::new(KeyCode::Tab, KeyModifiers::NONE));
        let Some(Dialog::CdpBrowser { group_focus, .. }) = &app.dialog else { panic!("no dialog") };
        assert!(!group_focus, "Tab toggles — a second press returns focus to the process list");
    }

    /// Highlighting a real `subcategory` group filters `entries` down to exactly the
    /// processes in that subcategory — the reason the groups column exists at all.
    #[test]
    fn selecting_a_group_filters_the_process_list_by_subcategory() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        app.open_cdp_browser();
        let Some(Dialog::CdpBrowser { groups, entries, .. }) = &app.dialog else { panic!("no dialog") };
        assert!(groups.len() > 2, "need at least one real subcategory group");
        let target_group = groups[2].clone();
        let unfiltered_count = entries.len();

        // All(0) -> Recent(1) -> the first real subcategory(2).
        app.cdp_browser_move_group(2);
        let Some(Dialog::CdpBrowser { entries, group_selected, .. }) = &app.dialog else { panic!("no dialog") };
        assert_eq!(*group_selected, 2);
        assert!(!entries.is_empty(), "the chosen group came from the catalog's own subcategories, so it must have members");
        assert!(entries.len() <= unfiltered_count);
        for &i in entries {
            assert_eq!(app.cdp_catalog.processes[i].subcategory, target_group);
        }
    }

    /// Typing into `search` while a real subcategory group is highlighted narrows within
    /// that group rather than replacing its filter — group AND search compose, they don't
    /// override each other (per the user's own refinement of the Phase 7 design: "Search
    /// narrows within the highlighted group").
    #[test]
    fn search_narrows_within_the_highlighted_group() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        app.open_cdp_browser();
        app.cdp_browser_move_group(2); // the first real subcategory group
        let Some(Dialog::CdpBrowser { entries, group_selected: 2, .. }) = &app.dialog else {
            panic!("expected group index 2 to be selected")
        };
        let unfiltered_count = entries.len();
        let sample_index = entries[0];
        let sample_key = app.cdp_catalog.processes[sample_index].key.clone();

        for c in sample_key.chars() {
            app.handle_dialog_key(KeyEvent::new(KeyCode::Char(c), KeyModifiers::NONE));
        }
        let Some(Dialog::CdpBrowser { entries, group_selected, .. }) = &app.dialog else { panic!("no dialog") };
        assert_eq!(*group_selected, 2, "typing must not disturb the highlighted group");
        assert!(entries.len() <= unfiltered_count, "a specific-enough query should narrow, not widen, the group's results");
        assert!(entries.contains(&sample_index), "the sampled entry's own key must still match a search for exactly that key");
    }

    /// Search matches a process's *name* (`key`/`title`) only — a term that only appears in
    /// `short_description`/`description` must not match, or the search box effectively
    /// searches everything rather than narrowing by name (the user-reported confusion this
    /// fixes: `blur_avrg`'s key is "blur_avrg", and its description happens to say "adjacent
    /// channels" — a word neither its key nor its CDP-WASM-SUITE-style title ("Spectral
    /// Average — blur", see `CDP-WASM-SUITE-analysis.md`'s rename pass) mentions).
    #[test]
    fn search_matches_process_name_not_description() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        let blur_avrg = app.cdp_catalog.processes.iter().position(|p| p.key == "blur_avrg").expect("blur_avrg in catalog");
        assert!(
            app.cdp_catalog.processes[blur_avrg].short_description.to_lowercase().contains("channels"),
            "test assumes blur_avrg's short_description mentions \"channels\" while its name doesn't"
        );
        assert!(
            !app.cdp_catalog.processes[blur_avrg].title.to_lowercase().contains("channels"),
            "test assumes blur_avrg's title doesn't also mention \"channels\""
        );

        app.open_cdp_browser();
        for c in "channels".chars() {
            app.handle_dialog_key(KeyEvent::new(KeyCode::Char(c), KeyModifiers::NONE));
        }
        let Some(Dialog::CdpBrowser { entries, .. }) = &app.dialog else { panic!("no dialog") };
        assert!(
            !entries.contains(&blur_avrg),
            "a description-only term must not match — search is name-only, not full-text"
        );
    }

    /// Right arrow while the Groups column has focus steps into the Processes column — the
    /// natural "step right" reading of the key, distinct from Tab's plain toggle. Right in
    /// the Processes column stays search-cursor movement (there's no column further right to
    /// step into).
    #[test]
    fn right_arrow_in_groups_column_moves_focus_to_processes() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        app.open_cdp_browser();
        app.handle_dialog_key(KeyEvent::new(KeyCode::Tab, KeyModifiers::NONE));
        let Some(Dialog::CdpBrowser { group_focus, .. }) = &app.dialog else { panic!("no dialog") };
        assert!(*group_focus, "Tab should have moved focus to Groups");

        app.handle_dialog_key(KeyEvent::new(KeyCode::Right, KeyModifiers::NONE));
        let Some(Dialog::CdpBrowser { group_focus, .. }) = &app.dialog else { panic!("no dialog") };
        assert!(!group_focus, "Right out of Groups should move focus to Processes");
    }

    /// Left arrow while the Processes column has focus steps back into Groups — the mirror
    /// image of `right_arrow_in_groups_column_moves_focus_to_processes` above. Left while
    /// already in Groups stays search-cursor movement (there's no column further left).
    #[test]
    fn left_arrow_in_processes_column_moves_focus_to_groups() {
        let mut app = new_app(Some(doc(0.1, 100)), None);
        app.open_cdp_browser();
        let Some(Dialog::CdpBrowser { group_focus, .. }) = &app.dialog else { panic!("no dialog") };
        assert!(!group_focus, "should start with the process list focused");

        app.handle_dialog_key(KeyEvent::new(KeyCode::Left, KeyModifiers::NONE));
        let Some(Dialog::CdpBrowser { group_focus, .. }) = &app.dialog else { panic!("no dialog") };
        assert!(*group_focus, "Left out of Processes should move focus to Groups");

        // Left again, now already in Groups, has nowhere further left to step — falls
        // through to search-cursor movement, leaving focus on Groups unchanged.
        app.handle_dialog_key(KeyEvent::new(KeyCode::Left, KeyModifiers::NONE));
        let Some(Dialog::CdpBrowser { group_focus, .. }) = &app.dialog else { panic!("no dialog") };
        assert!(*group_focus, "Left while already in Groups should leave focus unchanged");
    }

    /// `Dialog::CdpBrowser.recent`'s order (most-recently-used first, from
    /// `model::cdp::recent::load_recent`) is what the "Recent" group actually shows — not
    /// catalog order, which would defeat the point of a recency-ordered shortcut list.
    #[test]
    fn recent_group_shows_most_recently_used_first() {
        let _guard = crate::config::XDG_CONFIG_HOME_TEST_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        let temp_dir = std::env::temp_dir().join(format!("tui_wave_cdp_recent_group_test_{}", std::process::id()));
        std::fs::create_dir_all(&temp_dir).unwrap();
        unsafe { std::env::set_var("XDG_CONFIG_HOME", &temp_dir) };

        let mut app = new_app(Some(doc(0.1, 100)), None);
        let first_key = app.cdp_catalog.processes[0].key.clone();
        let second_key = app.cdp_catalog.processes[1].key.clone();
        crate::model::cdp::recent::record_used(&first_key);
        crate::model::cdp::recent::record_used(&second_key);

        app.open_cdp_browser();
        app.cdp_browser_move_group(1); // All(0) -> Recent(1)
        let Some(Dialog::CdpBrowser { entries, group_selected: 1, .. }) = &app.dialog else {
            panic!("expected the Recent group to be selected")
        };
        let keys: Vec<&str> = entries.iter().map(|&i| app.cdp_catalog.processes[i].key.as_str()).collect();
        assert_eq!(keys, vec![second_key.as_str(), first_key.as_str()], "most-recently-used should come first");

        unsafe { std::env::remove_var("XDG_CONFIG_HOME") };
        std::fs::remove_dir_all(&temp_dir).ok();
    }

    /// A successful Apply — the normal single-result splice path through `tick_cdp` — records
    /// the process as recently used, so it shows up in the browser's "Recent" group next time
    /// it's opened. Preview alone must not (see the other assertion below).
    #[test]
    fn applying_a_process_records_it_as_recently_used() {
        let _guard = crate::config::XDG_CONFIG_HOME_TEST_LOCK.lock().unwrap_or_else(|e| e.into_inner());
        let temp_dir = std::env::temp_dir().join(format!("tui_wave_cdp_recent_apply_test_{}", std::process::id()));
        std::fs::create_dir_all(&temp_dir).unwrap();
        unsafe { std::env::set_var("XDG_CONFIG_HOME", &temp_dir) };

        let mut app = new_app(Some(doc(0.1, 4)), None);
        let catalog_index = 0;
        let expected_key = app.cdp_catalog.processes[catalog_index].key.clone();
        assert!(crate::model::cdp::recent::load_recent().is_empty(), "nothing recorded yet");

        app.cdp_pending = Some(CdpPending {
            doc_index: 0,
            range: (0, 4),
            label: "CDP: Fake".into(),
            catalog_index,
            fields: Vec::new(),
            second_input: None,
            focus: 0,
            presets: Vec::new(),
            preset_selected: None,
        });
        app.dialog = Some(Dialog::CdpRunning {
            job_id: 99,
            title: "Fake".into(),
            step_label: String::new(),
            step_index: 0,
            step_total: 1,
            started: std::time::Instant::now(),
            purpose: crate::cdp::JobPurpose::Apply,
        });

        let planned = crate::model::cdp::pipeline::PlannedJob {
            steps: vec![crate::model::cdp::pipeline::Invocation {
                bin: "cp".into(),
                args: vec!["in.wav".into(), "out.wav".into()],
                label: "fake copy".into(),
                expected_output: "out.wav".into(),
            }],
            input_files: vec![crate::model::cdp::pipeline::TempWavSpec {
                relative_name: "in.wav".into(),
                input_index: 0,
                source_channels: vec![0],
            }],
            output_files: vec![crate::model::cdp::pipeline::OutputWavSpec {
                relative_name: "out.wav".into(),
                dest_channels: vec![0],
            }],
            glob_output: None,
            output_curve: None,
            output_curve_binary_template: None, output_formant_buffer: None,
            brk_files: Vec::new(),
            binary_input_files: Vec::new(),
            deferred_window_params: Vec::new(),
            needs_simple_wav_input: false,
        };
        app.cdp_runner.submit(crate::cdp::Job {
            id: 99,
            cdp_dir: std::path::PathBuf::from("/bin"),
            planned,
            inputs: vec![vec![vec![0.1, 0.2, 0.3, 0.4]]],
            input_sample_rate: app.documents[0].sample_rate,
            purpose: crate::cdp::JobPurpose::Apply,
        });

        let deadline = std::time::Instant::now() + Duration::from_secs(5);
        while app.dialog.is_some() && std::time::Instant::now() < deadline {
            app.tick_cdp();
            std::thread::sleep(Duration::from_millis(5));
        }
        assert!(app.dialog.is_none(), "the CdpRunning dialog should close once the job finishes");

        assert_eq!(
            crate::model::cdp::recent::load_recent(),
            vec![expected_key],
            "a successful Apply should record the process as recently used"
        );

        unsafe { std::env::remove_var("XDG_CONFIG_HOME") };
        std::fs::remove_dir_all(&temp_dir).ok();
    }

